// VoiceCallEntity.kt
@Entity
@Table(catalog = "maum", name = "voice_call")
class VoiceCallEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    val callerId: String,             // 발신자 userId
    val receiverId: String,           // 수신자 userId
    val matchRequestId: String? = null, // 연결된 매칭 요청 (nullable)
    val channelId: String,            // WebRTC/Agora 채널 ID
    val status: Int,                  // 0=대기, 1=진행중, 2=종료, 3=거절
    var durationSeconds: Int? = null, // 통화 시간(초)
    var endedAt: LocalDateTime? = null,

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),

    @LastModifiedDate
    var updatedAt: LocalDateTime = LocalDateTime.now(),
)
