## 3. GraphQL 스키마 설계

**파일 위치: `graphql/src/main/resources/graphql/schema.graphqls`**

```graphql
# ──────────────────────────────
# 공통 스칼라
# ──────────────────────────────
scalar DateTime

# ──────────────────────────────
# 루트 타입
# ──────────────────────────────
type Query
type Mutation
```

**파일 위치: `graphql/src/main/resources/graphql/user.graphqls`**

```graphql
type User {
    id: ID!
    nickname: String!
    gender: String!
    birthDate: String!
    profile: UserProfile
    photos: [UserPhoto!]!
    mannerScore: Float!
    isFollowing: Boolean!
    createdAt: DateTime!
}

type UserProfile {
    bio: String
    job: String
    location: String
    height: Int
    mbti: String
    voiceIntroUrl: String
}

type UserPhoto {
    id: ID!
    photoUrl: String!
    order: Int!
}

# 간략 정보 (리스트/매칭 추천 화면용)
type SimpleUser {
    id: ID!
    nickname: String!
    gender: String!
    profilePhotoUrl: String
    mannerScore: Float!
}

input UpdateProfileInput {
    bio: String
    job: String
    location: String
    height: Int
    mbti: String
}

extend type Query {
    me: User!
    user(userId: ID!): User
    recommendedUsers(limit: Int, offset: Int): [SimpleUser!]!
}

extend type Mutation {
    updateProfile(input: UpdateProfileInput!): UserProfile!
    uploadProfilePhoto(order: Int!): String!  # presigned URL 반환
    deleteProfilePhoto(photoId: ID!): Boolean!
}
```

**파일 위치: `graphql/src/main/resources/graphql/call.graphqls`**

```graphql
type VoiceCall {
    id: ID!
    caller: SimpleUser!
    receiver: SimpleUser!
    status: CallStatus!
    channelId: String!
    durationSeconds: Int
    createdAt: DateTime!
    endedAt: DateTime
}

enum CallStatus {
    WAITING
    IN_PROGRESS
    ENDED
    REJECTED
}

type CallHistory {
    id: ID!
    partner: SimpleUser!
    durationSeconds: Int
    createdAt: DateTime!
}

extend type Query {
    callHistory(limit: Int, offset: Int): [CallHistory!]!
    activeCall: VoiceCall
}

extend type Mutation {
    startCall(receiverId: ID!): VoiceCall!
    acceptCall(callId: ID!): VoiceCall!
    rejectCall(callId: ID!): Boolean!
    endCall(callId: ID!): VoiceCall!
}
```

**파일 위치: `graphql/src/main/resources/graphql/match.graphqls`**

```graphql
type MatchRequest {
    id: ID!
    sender: SimpleUser!
    receiver: SimpleUser!
    status: MatchStatus!
    createdAt: DateTime!
    respondedAt: DateTime
}

enum MatchStatus {
    PENDING
    ACCEPTED
    REJECTED
    EXPIRED
}

input SendMatchRequestInput {
    receiverId: ID!
}

extend type Query {
    receivedMatchRequests: [MatchRequest!]!
    sentMatchRequests: [MatchRequest!]!
}

extend type Mutation {
    sendMatchRequest(input: SendMatchRequestInput!): MatchRequest!
    acceptMatchRequest(matchRequestId: ID!): MatchRequest!
    rejectMatchRequest(matchRequestId: ID!): MatchRequest!
}
```

**파일 위치: `graphql/src/main/resources/graphql/follow.graphqls`**

```graphql
type FollowResult {
    followerId: ID!
    followingId: ID!
    createdAt: DateTime!
}

extend type Query {
    followers(userId: ID!, limit: Int, offset: Int): [SimpleUser!]!
